// ============================================================
// RESEARCH LOOP + INFORME -- multi-proveedor (APIs gratis)
// Bucle: SEARCH (Tavily) -> FETCH -> ANALYZE (LLM) -> DECIDE
// LLM con fallback: groq -> cerebras -> azure -> ollama (local)
// Todo en un solo Code node: menos nodos = menos puntos de falla.
// ============================================================

const cfg = $input.first().json;
if (!cfg.topic) throw new Error('body.topic requerido');
if (!cfg.tavilyApiKey) throw new Error('Falta Tavily key (body.tavily_api_key o env TAVILY_API_KEY)');

const t0 = Date.now();
// Arrow function: captura el `this` del sandbox de n8n.
// (function declarations rompen this.helpers -- bug de la version anterior)
const httpRequest = async (opts) => await this.helpers.httpRequest(opts);

const msgs = (system, user) => system
  ? [{ role: 'system', content: system }, { role: 'user', content: user }]
  : [{ role: 'user', content: user }];

const PROVIDERS = {
  groq: {
    ok: () => !!cfg.groqApiKey,
    call: async (system, user, maxTok) => {
      const r = await httpRequest({
        method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + cfg.groqApiKey, 'Content-Type': 'application/json' },
        body: { model: cfg.groqModel, messages: msgs(system, user), temperature: 0.3, max_tokens: maxTok },
        json: true, timeout: 60000,
      });
      return ((r.choices && r.choices[0].message.content) || '').trim();
    },
  },
  cerebras: {
    ok: () => !!cfg.cerebrasApiKey,
    call: async (system, user, maxTok) => {
      const r = await httpRequest({
        method: 'POST', url: 'https://api.cerebras.ai/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + cfg.cerebrasApiKey, 'Content-Type': 'application/json' },
        // gpt-oss-120b razona antes de responder: margen extra de tokens
        body: { model: cfg.cerebrasModel, messages: msgs(system, user), max_completion_tokens: maxTok + 2048 },
        json: true, timeout: 60000,
      });
      return ((r.choices && r.choices[0].message.content) || '').trim();
    },
  },
  azure: {
    ok: () => !!(cfg.azureApiKey && cfg.azureEndpoint && cfg.azureDeployment),
    call: async (system, user, maxTok) => {
      const base = String(cfg.azureEndpoint).replace(/\/+$/, '');
      const r = await httpRequest({
        method: 'POST',
        url: base + '/openai/deployments/' + cfg.azureDeployment + '/chat/completions?api-version=2024-10-21',
        headers: { 'api-key': cfg.azureApiKey, 'Content-Type': 'application/json' },
        // gpt-5-mini: NO acepta temperature custom; razona -> margen extra
        body: { messages: msgs(system, user), max_completion_tokens: maxTok + 2048 },
        json: true, timeout: 90000,
      });
      return ((r.choices && r.choices[0].message.content) || '').trim();
    },
  },
  ollama: {
    ok: () => !!cfg.ollamaBaseUrl,
    call: async (system, user, maxTok) => {
      const r = await httpRequest({
        method: 'POST', url: String(cfg.ollamaBaseUrl).replace(/\/+$/, '') + '/api/generate',
        headers: { 'Content-Type': 'application/json' },
        body: {
          model: cfg.ollamaModel,
          prompt: system ? system + '\n\n' + user : user,
          stream: false,
          options: { temperature: 0.3, num_predict: maxTok },
        },
        json: true, timeout: 300000,
      });
      return (r.response || '').trim();
    },
  },
};

const providerOrder = String(cfg.providerOrder || 'groq,cerebras,azure,ollama')
  .split(',').map((s) => s.trim()).filter((p) => PROVIDERS[p] && PROVIDERS[p].ok());
if (!providerOrder.length) throw new Error('Ningun proveedor LLM configurado (keys vacias)');

const llmStats = {};   // proveedor -> llamadas exitosas
const errors = [];     // errores no fatales (para meta)

const callLLM = async (system, user, maxTok) => {
  let lastErr = null;
  for (const name of providerOrder) {
    try {
      const text = await PROVIDERS[name].call(system, user, maxTok || 1024);
      if (text) { llmStats[name] = (llmStats[name] || 0) + 1; return text; }
      lastErr = new Error(name + ' devolvio vacio');
    } catch (e) {
      lastErr = e;
      errors.push(name + ': ' + String((e && e.message) || e).slice(0, 160));
    }
  }
  throw new Error('Todos los proveedores LLM fallaron. Ultimo error: ' + (lastErr && lastErr.message));
};

const searchTavily = async (query) => {
  try {
    return await httpRequest({
      method: 'POST', url: 'https://api.tavily.com/search',
      headers: { Authorization: 'Bearer ' + cfg.tavilyApiKey, 'Content-Type': 'application/json' },
      body: {
        query,
        search_depth: cfg.searchDepth || 'basic', // basic = 1 credito, advanced = 2
        max_results: 5,
        include_answer: true,
        include_raw_content: false,
      },
      json: true, timeout: 30000,
    });
  } catch (e) {
    errors.push('tavily: ' + String((e && e.message) || e).slice(0, 160));
    return { results: [], answer: null };
  }
};

const fetchUrlContent = async (url) => {
  try {
    const body = await httpRequest({
      method: 'GET', url, timeout: 12000, json: false,
      headers: { 'User-Agent': 'Mozilla/5.0 (ResearchBot/1.0)' },
    });
    let text = typeof body === 'string' ? body : JSON.stringify(body);
    text = text
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&[a-z#0-9]+;/gi, ' ')
      .replace(/\s+/g, ' ').trim();
    return text.slice(0, 4000);
  } catch (e) {
    return '';
  }
};

// ---------------- BUCLE PRINCIPAL ----------------
const maxIterations = Math.min(Math.max(parseInt(cfg.maxIterations, 10) || 4, 1), 10);
const findings = [];
const queryHistory = [];
const seenUrls = new Set(); // dedupe entre iteraciones (la v1 re-bajaba las mismas URLs)
let currentQuery = cfg.topic;

for (let i = 0; i < maxIterations; i++) {
  queryHistory.push(currentQuery);
  const search = await searchTavily(currentQuery);

  if (search.answer) {
    findings.push({ type: 'tavily_answer', iteration: i + 1, query: currentQuery, content: search.answer });
  }

  const fresh = (search.results || []).filter((r) => r.url && !seenUrls.has(r.url)).slice(0, 3);
  for (const r of fresh) {
    seenUrls.add(r.url);
    const raw = await fetchUrlContent(r.url);
    const content = raw.length > 200 ? raw : (r.content || raw);
    if (!content) continue;

    const analysis = await callLLM(
      'Eres un asistente de investigacion. Analizas contenido web y devuelves SOLO JSON valido, sin markdown ni texto extra.',
      'Tema: "' + cfg.topic + '"\nTITULO: ' + (r.title || '') + '\nURL: ' + r.url +
      '\n\nCONTENIDO:\n' + content +
      '\n\nDevuelve JSON: {"key_facts":["..."],"relevance":"alta|media|baja","summary":"2-3 frases","new_angles":["..."]}',
      900,
    );
    let parsed;
    try {
      parsed = JSON.parse(analysis.replace(/```json\n?|```\n?/g, '').trim());
    } catch (e) {
      parsed = { raw_analysis: analysis.slice(0, 1500) };
    }
    findings.push({ type: 'web_analysis', iteration: i + 1, query: currentQuery, title: r.title, url: r.url, analysis: parsed });
  }

  if (i === maxIterations - 1) break; // ultima vuelta: no gastar la llamada DECIDIR

  const decision = await callLLM(
    null,
    'Eres agente de investigacion. Tema: "' + cfg.topic + '". Iteracion ' + (i + 1) + '/' + maxIterations +
    '.\nHallazgos recientes:\n' + JSON.stringify(findings.slice(-5)).slice(0, 6000) +
    '\n\nSi la informacion ya cubre el tema responde EXACTAMENTE "FINALIZAR: <razon breve>". ' +
    'Si falta, responde EXACTAMENTE "CONTINUAR: <nueva consulta concreta>". ' +
    'No repitas estas consultas ya hechas: ' + queryHistory.join(' | '),
    300,
  );

  if (/^\s*FINALIZAR/i.test(decision)) break;
  const m = decision.match(/CONTINUAR:?\s*(.+)/i);
  let next = m ? m[1].trim().replace(/^["']|["']$/g, '') : '';
  if (!next || queryHistory.some((q) => q.toLowerCase() === next.toLowerCase())) {
    next = cfg.topic + ' (angulo ' + (i + 2) + ')';
  }
  currentQuery = next.slice(0, 300);
}

// ---------------- INFORME FINAL ----------------
const sources = [...new Set(findings.filter((f) => f.url).map((f) => f.url))];
let report;
try {
  report = await callLLM(
    'Eres un investigador senior. Redactas informes claros en espanol, en formato Markdown.',
    'Genera un informe con secciones: 1. RESUMEN EJECUTIVO, 2. HALLAZGOS PRINCIPALES (cita fuente URL), ' +
    '3. ANALISIS CRITICO, 4. LAGUNAS DE INFORMACION, 5. PROXIMOS PASOS.\n\n' +
    'TEMA: "' + cfg.topic + '"\n\nHALLAZGOS:\n' + JSON.stringify(findings, null, 1).slice(0, 14000) +
    '\n\nFUENTES:\n' + sources.join('\n'),
    2000,
  );
} catch (e) {
  report = '[Informe no generado: ' + e.message + '] Revisar meta.errors y findings crudos.';
}

return [{
  json: {
    topic: cfg.topic,
    report,
    meta: {
      iterations: queryHistory.length,
      queries: queryHistory,
      findingsCount: findings.length,
      sources,
      llmCalls: llmStats,
      providerOrder,
      errors: errors.slice(0, 20),
      ms: Date.now() - t0,
    },
    findings,
  },
}];
